/// <summary>
/// Item import
/// </summary>
public class ETG_Acu_EcoResReleasedProdMasterImport extends ETG_Acu_DataImportBase
{
}

Method.Source:
public static void main(Args args)
{
    ETG_Acu_EcoResReleasedProdMasterImport  releasedProdImport;

    releasedProdImport = ETG_Acu_EcoResReleasedProdMasterImport::construct();

    if (releasedProdImport.prompt())
    {
        releasedProdImport.runOperation();
    }
}

public static ETG_Acu_EcoResReleasedProdMasterImport construct()
{
    return new ETG_Acu_EcoResReleasedProdMasterImport();
}

/// <summary>
/// Describes whether the class is designed for execution in a new session.
/// </summary>
/// <returns>
/// true if the class is designed for execution the operation in a new session; otherwise, false.
/// </returns>
protected boolean canRunInNewSession()
{
    return false;
}

protected void processData(container _con)
{
    EcoResReleasedProductCreationV2Entity       releasedProd;
    EcoResProductDisplayProductNumber           prodNum;

    DictEnum            dictEnumProdSubType = new DictEnum(enumNum(EcoResProductSubtype));
    DictEnum            dictEnumProdType = new DictEnum(enumNum(EcoResProductType));
    DictEnum            dictEnumVariantTech = new DictEnum(enumNum(EcoResVariantConfigurationTechnologyType));

    prodNum     = conpeek(_con, 1);

    select firstonly forupdate releasedProd
        where releasedProd.ItemNumber == prodNum;

    if (!releasedProd)
    {
        releasedProd.ItemNumber                     = prodNum;
        releasedProd.BOMUnitSymbol                  = conpeek(_con, 2);
        releasedProd.InventoryUnitSymbol            = conpeek(_con, 3);
        releasedProd.ItemModelGroupId               = conpeek(_con, 4);
        releasedProd.ProductDimensionGroupName      = conpeek(_con, 5);
        releasedProd.ProductGroupId                 = conpeek(_con, 6);
        releasedProd.ProductName                    = conpeek(_con, 7);
        releasedProd.ProductNumber                  = conpeek(_con, 8);
        releasedProd.ProductSearchName              = conpeek(_con, 9);
        releasedProd.ProductSubType                 = dictEnumProdSubType.symbol2Value(conpeek(_con, 10));
        releasedProd.ProductType                    = dictEnumProdType.symbol2Value(conpeek(_con, 11));
        releasedProd.PurchaseUnitSymbol             = conpeek(_con, 12);
        releasedProd.SalesSalesTaxItemGroupCode     = conpeek(_con, 13);
        releasedProd.SalesUnitSymbol                = conpeek(_con, 14);
        releasedProd.SearchName                     = conpeek(_con, 15);
        releasedProd.StorageDimensionGroupName      = conpeek(_con, 16);
        releasedProd.TrackingDimensionGroupName     = conpeek(_con, 17);
        releasedProd.VariantConfigurationTechnology = dictEnumVariantTech.symbol2Value(conpeek(_con, 18));
        releasedProd.insert();
    }
    else
    {
        releasedProd.BOMUnitSymbol                  = conpeek(_con, 2);
        releasedProd.InventoryUnitSymbol            = conpeek(_con, 3);
        releasedProd.ItemModelGroupId               = conpeek(_con, 4);
        releasedProd.ProductDimensionGroupName      = conpeek(_con, 5);
        releasedProd.ProductGroupId                 = conpeek(_con, 6);
        releasedProd.ProductName                    = conpeek(_con, 7);
        releasedProd.ProductNumber                  = conpeek(_con, 8);
        releasedProd.ProductSearchName              = conpeek(_con, 9);
        releasedProd.ProductSubType                 = dictEnumProdSubType.symbol2Value(conpeek(_con, 10));
        releasedProd.ProductType                    = dictEnumProdType.symbol2Value(conpeek(_con, 11));
        releasedProd.PurchaseUnitSymbol             = conpeek(_con, 12);
        releasedProd.SalesSalesTaxItemGroupCode     = conpeek(_con, 13);
        releasedProd.SalesUnitSymbol                = conpeek(_con, 14);
        releasedProd.SearchName                     = conpeek(_con, 15);
        releasedProd.StorageDimensionGroupName      = conpeek(_con, 16);
        releasedProd.TrackingDimensionGroupName     = conpeek(_con, 17);
        releasedProd.VariantConfigurationTechnology = dictEnumVariantTech.symbol2Value(conpeek(_con, 18));
        releasedProd.update();
    }
}

/// <summary>
/// Import colors
/// </summary>
/// <returns>Caption</returns>
public ClassDescription caption()
{
    ClassDescription ret;

    ret = "@ETG_ENG_Labels:ImpItem";

    return ret;
}
